const data = $input.first().json.body;

// ========== LOGS DE DEBUG ==========
console.log('🔍 Datos recibidos del webhook:');
console.log('  - Email TO:', data.email);
console.log('  - CC Empresa:', data.cc_email);
console.log('  - CC BD:', data.correo_bd);
console.log('  - WhatsApp números:', data.whatsapp);
console.log('  - WhatsApp mensaje:', data.whatsapp_message ? 'Presente' : 'Ausente');
console.log('  - Serial:', data.serial);

// ========== PROCESAR EMAILS CC ==========
let cc_emails = [];

// Agregar CC de empresa si existe
if (data.cc_email && data.cc_email.trim()) {
  const empresaCCs = data.cc_email
    .split(',')
    .map(e => e.trim())
    .filter(e => e.includes('@') && e.length > 5);
  cc_emails.push(...empresaCCs);
}

// Agregar CC de BD si existe
if (data.correo_bd && data.correo_bd.trim()) {
  const bdCCs = data.correo_bd
    .split(',')
    .map(e => e.trim())
    .filter(e => e.includes('@') && e.length > 5);
  cc_emails.push(...bdCCs);
}

// Eliminar duplicados (case-insensitive)
const uniqueEmails = new Set();
cc_emails = cc_emails.filter(email => {
  const lowerEmail = email.toLowerCase();
  if (uniqueEmails.has(lowerEmail)) {
    return false;
  }
  uniqueEmails.add(lowerEmail);
  return true;
});

// Eliminar el TO de los CCs si está incluido
if (data.email) {
  const toLower = data.email.toLowerCase();
  cc_emails = cc_emails.filter(e => e.toLowerCase() !== toLower);
}

// ========== PROCESAR TELÉFONOS WHATSAPP ==========
let whatsapp_numbers = [];

if (data.whatsapp && data.whatsapp.trim()) {
  whatsapp_numbers = data.whatsapp
    .split(',')
    .map(num => {
      // Limpiar número (solo dígitos)
      let clean = num.trim().replace(/[^0-9]/g, '');

      // Formato Colombia: 57XXXXXXXXXX (12 dígitos sin +)
      if (clean.startsWith('57') && clean.length === 12) {
        return clean; // Ya tiene formato correcto
      }
      if (clean.length === 10) {
        return '57' + clean; // Número colombiano sin código
      }
      return clean;
    })
    .filter(num => num.length === 12); // Exactamente 12 dígitos (57 + 10)
}

// ========== CONVERTIR HTML A TEXTO PARA WHATSAPP ==========
let whatsapp_text = data.whatsapp_message || '';

if (!data.whatsapp_message && data.html_content) {
  // Extraer texto limpio del HTML
  whatsapp_text = data.html_content
    .replace(/<style[^>]*>.*?<\/style>/gi, '') // Quitar CSS
    .replace(/<script[^>]*>.*?<\/script>/gi, '') // Quitar JS
    .replace(/<br\s*\/?>/gi, '\n')              // BR a salto de línea
    .replace(/<\/p>/gi, '\n\n')                 // Párrafos
    .replace(/<\/div>/gi, '\n')                 // Divs
    .replace(/<li>/gi, '• ')                      // Listas
    .replace(/<[^>]+>/g, '')                      // Quitar todos los tags
    .replace(/&nbsp;/g, ' ')                      // Entities
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\n{3,}/g, '\n\n')                  // Máximo 2 saltos seguidos
    .replace(/[ \t]+/g, ' ')                      // Múltiples espacios
    .trim();

  // Limitar a 1500 caracteres (WhatsApp permite ~4096)
  if (whatsapp_text.length > 1500) {
    whatsapp_text = whatsapp_text.substring(0, 1497) + '...';
  }
}

// Agregar header personalizado para WhatsApp si hay serial
if (data.serial && whatsapp_text) {
  whatsapp_text = `📋 *Incapacidad ${data.serial}*\n\n${whatsapp_text}\n\n_Mensaje automático - IncaNeurobaeza_`;
}

console.log('\n✅ Datos procesados:');
console.log('📧 Email TO:', data.email);
console.log('📧 Email CCs:', cc_emails);
console.log('📱 WhatsApp números:', whatsapp_numbers);
console.log('📱 WhatsApp texto (preview):', whatsapp_text.substring(0, 100));
console.log('📋 Serial:', data.serial);

return {
  json: {
    // Datos email (originales)
    email: data.email,
    subject: data.subject,
    html_content: data.html_content,
    cc_emails: cc_emails,
    serial: data.serial,
    tipo_notificacion: data.tipo_notificacion,

    // Datos WhatsApp (nuevos)
    whatsapp_numbers: whatsapp_numbers,
    whatsapp_text: whatsapp_text,

    // Flags de control
    send_email: data.email && data.email.trim().length > 0,
    send_whatsapp: whatsapp_numbers.length > 0
  }
};

// Recopilar resultados de TODOS los canales
const allInputs = $input.all();
const originalData = $('Procesar Datos1').first().json;

// Detectar emails (tienen threadId o id de Gmail)
const emailResults = allInputs.filter(item => 
  item.json.threadId || 
  (item.json.id && typeof item.json.id === 'string' && item.json.id.length > 10)
);

// Detectar WhatsApp (tienen id de WAHA)
const whatsappResults = allInputs.filter(item => 
  item.json.id && item.json.timestamp && item.json.from
);

let response = {
  status: 'success',
  serial: originalData.serial || 'N/A',
  timestamp: new Date().toISOString(),
  channels: {}
};

// ========== RESULTADOS EMAIL ==========
if (emailResults.length > 0) {
  response.channels.email = {
    sent: true,
    to: originalData.email,
    cc: originalData.cc_emails || [],
    message_id: emailResults[0].json.id || emailResults[0].json.threadId || 'unknown'
  };
} else if (originalData.send_email) {
  response.channels.email = {
    sent: false,
    error: 'Email no enviado',
    to: originalData.email
  };
}

// ========== RESULTADOS WHATSAPP ==========
if (whatsappResults.length > 0) {
  const successCount = whatsappResults.filter(r => r.json.id).length;

  response.channels.whatsapp = {
    sent: true,
    total_numbers: originalData.whatsapp_numbers ? originalData.whatsapp_numbers.length : 0,
    successful: successCount,
    failed: (originalData.whatsapp_numbers ? originalData.whatsapp_numbers.length : 0) - successCount,
    numbers: originalData.whatsapp_numbers || []
  };
} else if (originalData.send_whatsapp) {
  response.channels.whatsapp = {
    sent: false,
    error: 'WhatsApp no enviado',
    numbers: originalData.whatsapp_numbers || []
  };
}

// Log para debugging
console.log('📊 Respuesta final:', JSON.stringify(response, null, 2));

return { json: response };
